/**
 * Handle different possible return formats from PDF extraction
 * @param {any} result - Result from PDF extraction function
 * @returns {string} Normalized text content
 */
export function normalizeExtractionResult(result) {
  if (typeof result === 'string') {
    return result;
  } else if (result && typeof result.text === 'string') {
    return result.text;
  } else if (result && Array.isArray(result.text)) {
    // Join array elements with double newlines to separate pages
    return result.text.join('\n\n');
  } else if (result && result.text) {
    return String(result.text);
  } else {
    return String(result || '');
  }
}

/**
 * Convert various input types to Uint8Array for consistent processing
 * @param {ArrayBuffer|Uint8Array|Buffer} data - Input data
 * @returns {Uint8Array} Converted data
 */
export function toUint8Array(data) {
  if (data instanceof ArrayBuffer) {
    return new Uint8Array(data);
  } else if (data instanceof Uint8Array) {
    return data;
  } else if (typeof Buffer !== 'undefined' && Buffer.isBuffer(data)) {
    return new Uint8Array(data);
  } else {
    throw new Error('Invalid input: expected ArrayBuffer, Uint8Array, or Buffer');
  }
}